def analyze_scenarios(migration_completion_year: int,
                      data_lifetime_years: int) -> dict:
    current_year = 2024
    data_expiry_year = current_year + data_lifetime_years

    scenarios = {
        'optimistic': 2030,
        'baseline': 2040,
        'conservative': 2050
    }

    results = {}

    for name, crqc_year in scenarios.items():
        # Is data protected when CRQC arrives?
        if migration_completion_year <= crqc_year:
            data_protected = True
            years_exposure = 0
        else:
            data_protected = False
            years_exposure = migration_completion_year - crqc_year

        # Does data still matter when CRQC arrives?
        data_still_sensitive = data_expiry_year > crqc_year

        # Risk level
        if not data_still_sensitive:
            risk = 'none'
        elif data_protected:
            risk = 'none'
        elif years_exposure > 5:
            risk = 'critical'
        elif years_exposure > 2:
            risk = 'high'
        else:
            risk = 'medium'

        results[f'{name}_crqc_{crqc_year}'] = {
            'crqc_year': crqc_year,
            'data_protected': data_protected,
            'years_exposure': years_exposure,
            'data_still_sensitive': data_still_sensitive,
            'risk_level': risk
        }

    # Overall recommendation
    has_critical = any(r['risk_level'] == 'critical' for r in results.values())
    has_high = any(r['risk_level'] == 'high' for r in results.values())

    if has_critical:
        overall = 'UNACCEPTABLE - Accelerate migration'
    elif has_high:
        overall = 'RISKY - Consider earlier completion'
    else:
        overall = 'ACCEPTABLE'

    results['overall_assessment'] = overall
    return results

def recommend_migration_year(data_lifetime: int,
                              risk_tolerance: str) -> int:
    current_year = 2024

    # CRQC estimate based on risk tolerance
    crqc_estimates = {
        'low': 2030,    # Assume worst case
        'medium': 2035,
        'high': 2040
    }

    crqc = crqc_estimates.get(risk_tolerance, 2035)

    # Must complete before CRQC or before data expires
    data_expiry = current_year + data_lifetime

    # Buffer based on risk tolerance
    buffer = {'low': 5, 'medium': 3, 'high': 1}.get(risk_tolerance, 3)

    target = min(crqc - buffer, data_expiry)

    # Can't complete before current year
    return max(current_year, target)
